const events = $input.all().map(i => i.json);
const datos = $('Normalizar Datos').first().json;

const hora = datos.hora;
const duracion = parseInt(datos.duracion) || 60;
const fechaDeseada = datos.fecha; // ej: "2026-03-27"

const [h, m] = hora.split(':').map(Number);
const inicioDeseado = h * 60 + m;
const finDeseado = inicioDeseado + duracion;

let conflicto = false;

for (const ev of events) {
  if (!ev.start || !ev.start.dateTime) continue;

  // ✅ Filtrar solo eventos del mismo día
  const fechaEvento = ev.start.dateTime.split('T')[0];
  if (fechaEvento !== fechaDeseada) continue;

  const s = new Date(ev.start.dateTime);
  const e = new Date(ev.end.dateTime);

  const ini = s.getHours() * 60 + s.getMinutes();
  // Si end === start (duración 0), asumir duración mínima del servicio
  const fin = (e.getTime() === s.getTime()) 
    ? ini + duracion 
    : e.getHours() * 60 + e.getMinutes();

  if (inicioDeseado < fin && finDeseado > ini) {
    conflicto = true;
    break;
  }
}

return [{ json: { disponible: !conflicto } }];

