parameters.jsCode:
// Horario configurable
const APERTURA = 9;  // 9:00
const CIERRE = 20;   // 20:00
const SLOT = 30;     // minutos por slot

const events = $input.all().map(i => i.json);
const fecha = $('Normalizar Datos').first().json.fecha;

// Rangos ocupados
const ocupados = [];
for (const ev of events) {
  if (!ev.start || !ev.start.dateTime) continue;
  const s = new Date(ev.start.dateTime);
  const e = new Date(ev.end.dateTime);
  ocupados.push({
    ini: s.getHours() * 60 + s.getMinutes(),
    fin: e.getHours() * 60 + e.getMinutes()
  });
}

// Generar slots libres
const slots = [];
for (let min = APERTURA * 60; min < CIERRE * 60; min += SLOT) {
  const slotFin = min + SLOT;
  const libre = !ocupados.some(o => min < o.fin && slotFin > o.ini);
  if (libre) {
    const hh = String(Math.floor(min / 60)).padStart(2, '0');
    const mm = String(min % 60).padStart(2, '0');
    slots.push(hh + ':' + mm);
  }
}

return [{ json: {
  status: 'ok',
  fecha,
  total_disponibles: slots.length,
  slots_disponibles: slots
} }];

